local redis = require "resty.redis"
local red = redis:new()

function load_plugin(code)
    local func, err = load(code, "=plugin", "t")
    if not func then
        error("Failed to load plugin: " .. err)
    end
    return func()
end

-- Load from Redis
local function load_from_redis(key)
    red:set_timeout(1000) -- 1 sec
    local res, err = red:get(key)
    if not res then
        ngx.log(ngx.ERR, "Failed to get plugin code from Redis: ", err)
        return nil
    end
    return load_plugin(res)
end

-- Load from HTTP headers
local function load_from_headers()
